function GetSkillImage(props) {
  const imageStyle = {
    width: '90%',
    height: '90%',
    borderRadius: '20px',
    // border: '2px solid #ccc',
    boxShadow: '0px 4px 10px rgba(0, 0, 0, 0.3)',
  };

  if (props.fileName === "DataScienceImg")
    return <img src={DataScienceImg} alt="Data Science" style={imageStyle} />;
  else if (props.fileName === "FullStackImg")
    return <img src={FullStackImg} alt="Full Stack" style={imageStyle} />;
  else if (props.fileName === "CloudInfraImg")
    return <img src={CloudInfraImg} alt="Cloud Infrastructure" style={imageStyle} />;
  return <img src={DesignImg} alt="Design" style={imageStyle} />;
}


